{
  "grammar": [
    {
      "pattern": "從 A 換到 B / 從 A 換 B 線",
      "structure": ["從 location/line A", "換", "到 location/line B / B 線"],
      "explanation_en": "Use this structure to indicate transferring from one transportation line or location to another.",
      "title": "Transferring Lines",
      "meaning": "Transfer from A to B",
      "when_to_use": ["When you need to change trains or buses", "When explaining a route with a transfer"],
      "when_not_to_use": ["When you are not changing lines", "When you are simply continuing on the same line"],
      "pragmatic_notes": "In Taiwan, you often hear '從紅線換到藍線' or '從台北車站換到板橋線'. It's common to specify the line color or station name.",
      "word_order_notes": "The structure is fixed: 從 + starting point + 換 + 到 + destination. The destination can be a line or a station.",
      "english_contrast": "In English, we say 'transfer from A to B'. In Chinese, the order is the same: 從 A 換到 B.",
      "korean_contrast": "In Korean, you might say 'A에서 B로 갈아타다'. The Chinese structure is similar: 從 A 換到 B.",
      "negative_examples": [
        {
          "text": "我換從紅線到藍線。",
          "error": "The word order is wrong. 從 must come before the starting point, not after the verb."
        }
      ],
      "incorrect_examples": [
        {
          "text": "我換線從紅線到藍線。",
          "error": "You don't need to say 換線 and then 從...到...; just use 從...換到..."
        }
      ],
      "transformation_drills": ["Change '從台北車站換到市政府站' to a question: '從台北車站換到市政府站嗎？'"],
      "production_drills": ["Tell your friend you need to transfer from the red line to the blue line at Taipei Main Station."],
      "common_error_patterns": ["Placing 從 after the verb", "Using 換線 redundantly with 從...到..."],
      "repair_feedback": {
        "word_order": "Remember: 從 comes first, then the starting point, then 換, then 到 + destination.",
        "politeness": "When asking for transfer information, use 請問 or 不好意思.",
        "vocabulary": "Use 換 for transferring lines; don't use 改 or 變."
      }
    },
    {
      "pattern": "坐錯 + vehicle/line / 走錯 + direction/location",
      "structure": ["verb (坐/走)", "錯", "object (車/線/路)"],
      "explanation_en": "Use this pattern to indicate taking the wrong vehicle, line, or going the wrong way.",
      "title": "Wrong Direction or Vehicle",
      "meaning": "Take the wrong (vehicle/line) or go the wrong way",
      "when_to_use": ["When you board the wrong bus or train", "When you go in the wrong direction", "When you take the wrong line"],
      "when_not_to_use": ["When you are simply lost without taking any transportation", "When the vehicle is correct but you missed your stop"],
      "pragmatic_notes": "In Taiwan, you often hear '我坐錯車了' or '我走錯路了'. It's common to add 了 at the end to indicate the mistake has already happened.",
      "word_order_notes": "The verb comes first, then 錯, then the object. For example: 坐錯車, 走錯路, 搭錯線.",
      "english_contrast": "In English, we say 'take the wrong bus' or 'go the wrong way'. In Chinese, the structure is verb + 錯 + object.",
      "korean_contrast": "In Korean, you might say '잘못 타다' or '잘못 가다'. The Chinese structure is similar but 錯 is placed after the verb.",
      "negative_examples": [
        {
          "text": "我錯坐車了。",
          "error": "錯 should come after the verb, not before it."
        }
      ],
      "incorrect_examples": [
        {
          "text": "我坐車錯了。",
          "error": "錯 should be placed directly after the verb, not at the end of the sentence."
        }
      ],
      "transformation_drills": ["Change '我坐錯車了' to a question: '你坐錯車了嗎？'"],
      "production_drills": ["Tell the station staff that you took the wrong line (e.g., red line instead of blue line)."],
      "common_error_patterns": ["Placing 錯 before the verb", "Placing 錯 at the end of the sentence"],
      "repair_feedback": {
        "word_order": "Remember: verb + 錯 + object. For example: 坐錯車, 走錯路.",
        "politeness": "When telling someone you made a mistake, use 不好意思 or 抱歉 first.",
        "vocabulary": "Use 坐錯 for vehicles, 走錯 for directions or locations, 搭錯 for lines."
      }
    },
    {
      "pattern": "還 + 沒 + verb + (呢)",
      "structure": ["還", "沒", "verb", "(呢)"],
      "explanation_en": "Use this pattern to indicate that an action has not yet happened, often with the expectation that it will happen soon.",
      "title": "Not Yet (還 + 沒)",
      "meaning": "Not yet (done something)",
      "when_to_use": ["When you haven't done something but plan to", "When answering a question about whether you've done something", "When something hasn't happened yet but is expected"],
      "when_not_to_use": ["When you never intend to do the action", "When the action is completed"],
      "pragmatic_notes": "In Taiwan, 還 + 沒 is very common in daily conversation. You can add 呢 at the end for a softer tone. For example: '我還沒吃飯呢。'",
      "word_order_notes": "還 comes before 沒, and 沒 comes before the verb. The structure is fixed: 還 + 沒 + verb.",
      "english_contrast": "In English, we say 'not yet' at the end of the sentence. In Chinese, 還沒 comes before the verb.",
      "korean_contrast": "In Korean, you might say '아직 안 + verb'. The Chinese structure is similar: 還 + 沒 + verb.",
      "negative_examples": [
        {
          "text": "我沒還吃飯。",
          "error": "還 must come before 沒, not after."
        }
      ],
      "incorrect_examples": [
        {
          "text": "我還沒吃飯了。",
          "error": "了 indicates completion, so it cannot be used with 還沒 which indicates non-completion."
        }
      ],
      "transformation_drills": ["Change '我還沒到站' to a question: '你還沒到站嗎？'"],
      "production_drills": ["Tell your friend that you haven't transferred yet (e.g., 我還沒換車)."],
      "common_error_patterns": ["Using 了 with 還沒", "Placing 還 after 沒"],
      "repair_feedback": {
        "word_order": "Remember: 還 + 沒 + verb. For example: 還沒到, 還沒換.",
        "politeness": "When saying you haven't done something, it's polite to add 不好意思 or 抱歉 if it causes inconvenience.",
        "vocabulary": "Use 還沒 for actions that haven't happened yet. Don't use 不 for this meaning."
      }
    }
  ]
}
